INSERT INTO tests(name,slug,short_name,description) VALUES('HAT Test Preparation','hat','HAT','HEC HAT preparation with modules and mock tests'),('LAT Preparation','lat','LAT','Law Admission Test preparation'),('ECAT Preparation','ecat','ECAT','Engineering entry preparation'),('MDCAT Preparation','mdcat','MDCAT','Medical entry preparation'),('Law GAT Preparation','lawgat','Law GAT','Law GAT preparation');
INSERT INTO levels(test_id,level_no,title,description) SELECT id,1,'Foundations',description FROM tests WHERE slug IN ('lat','ecat','mdcat','lawgat');
INSERT INTO levels(test_id,level_no,title,description) SELECT id,1,'Analytical Reasoning Foundations','Ordering, grouping, assignment questions and logical connectives' FROM tests WHERE slug='hat';
INSERT INTO levels(test_id,level_no,title,description) SELECT id,2,'Quantitative Reasoning Basics','Number system, HCF, LCM, fractions and exponents' FROM tests WHERE slug='hat';
INSERT INTO levels(test_id,level_no,title,description) SELECT id,3,'Verbal Reasoning Basics','Vocabulary, analogies and sentence completion' FROM tests WHERE slug='hat';
INSERT INTO topics(level_id,title,slug,category,order_no) SELECT id,'Logical Connectives','logical-connectives','Analytical',1 FROM levels WHERE level_no=1;
INSERT INTO topics(level_id,title,slug,category,order_no) SELECT id,'Ordering Questions','ordering-questions','Analytical',2 FROM levels WHERE level_no=1;
INSERT INTO topics(level_id,title,slug,category,order_no) SELECT id,'Number System','number-system','Quantitative',1 FROM levels WHERE level_no=2;
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Logical connectives','If A implies B, the valid equivalent is the contrapositive: not B implies not A. Do not reverse the statement.','Quick HAT Guide aligned concept' FROM topics WHERE slug='logical-connectives';
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Ordering method','Draw a diagram first. Immediately before means no item is between the two elements.','Quick HAT Guide aligned concept' FROM topics WHERE slug='ordering-questions';
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Number system','Natural, whole, integer, even, odd, prime and composite numbers are common HAT quantitative basics.','Quick HAT Guide aligned concept' FROM topics WHERE slug='number-system';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'If A implies B, which statement is logically equivalent?','B implies A','Not A implies Not B','Not B implies Not A','A and B are unrelated','C','The valid equivalent of A implies B is the contrapositive: not B implies not A.','medium','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=1 AND tp.level_id=l.id AND tp.slug='logical-connectives';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'In ordering questions, what does immediately before mean?','A can be anywhere before B','No element is between A and B','B is before A','A and B are separate groups','B','Immediately before means both items are adjacent with no item between them.','easy','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=1 AND tp.level_id=l.id AND tp.slug='ordering-questions';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'Which is the only even prime number?','1','2','4','6','B','2 is the only even prime number.','easy','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=2 AND tp.level_id=l.id AND tp.slug='number-system';
INSERT INTO topics(level_id,title,slug,category,order_no) SELECT id,'HCF and LCM','hcf-lcm','Quantitative',2 FROM levels WHERE level_no=2 AND test_id=(SELECT id FROM tests WHERE slug='hat');
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'HCF and LCM basics','HCF is the largest number that divides two numbers exactly. LCM is the smallest number divisible by both. Product of two numbers = HCF x LCM.','Quick HAT Guide aligned concept' FROM topics WHERE slug='hcf-lcm';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'HCF of 12 and 18 is:','2','4','6','12','C','12=2x2x3, 18=2x3x3, common factors 2x3=6.','easy','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=2 AND tp.level_id=l.id AND tp.slug='hcf-lcm';
INSERT INTO topics(level_id,title,slug,category,order_no) SELECT id,'Vocabulary and Analogies','vocabulary-analogies','Verbal',1 FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat');
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Analogy method','Identify the relationship between the first pair of words (cause-effect, part-whole, synonym, antonym), then find a pair with the exact same relationship.','Quick HAT Guide aligned concept' FROM topics WHERE slug='vocabulary-analogies';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'Doctor is to Hospital as Teacher is to:','Book','School','Student','Chalk','B','A doctor works at a hospital; a teacher works at a school (workplace relationship).','easy','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=3 AND tp.level_id=l.id AND tp.slug='vocabulary-analogies';
INSERT INTO topics(level_id,title,slug,category,order_no) SELECT id,'Sentence Completion','sentence-completion','Verbal',2 FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat');
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Sentence completion strategy','Read the full sentence first to understand the overall meaning and tone, then check which option logically and grammatically fits both blanks.','Quick HAT Guide aligned concept' FROM topics WHERE slug='sentence-completion';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'Despite his ____, he remained calm and ____.','anger / composed','joy / nervous','fear / panicked','wealth / poor','A','The contrast word despite signals an opposite pairing: anger followed by staying composed.','medium','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=3 AND tp.level_id=l.id AND tp.slug='sentence-completion';
